// ------- LEGAL Q&A -------
export type LegalShort = "Yes" | "No" | "It depends" | "Usually yes" | "Usually no";
export type LegalL = { id: string; q: Tx; short: LegalShort; answer: Tx; region?: Tx; source?: { label: string; url: string } };

const LEGAL_L: LegalL[] = [
  { id: "work-student", short: "Usually yes",
    q: { en: "Can I work on a student visa?", es: "¿Puedo trabajar con visado de estudiante?", fr: "Puis-je travailler avec un visa étudiant ?", de: "Darf ich mit Studentenvisum arbeiten?", it: "Posso lavorare con visto studio?", pt: "Posso trabalhar com visto de estudante?", pl: "Czy mogę pracować na wizie studenckiej?", uk: "Чи можу я працювати на студентській візі?" },
    answer: { en: "Most countries allow students to work part-time — typically 15–20 hours per week during term and full-time in holidays. Germany allows 140 full days / 280 half days a year, France 964 hours/year, the Netherlands 16 hours/week, the UK up to 20 hours/week.", es: "La mayoría permite trabajar parcial — normalmente 15–20 h/sem durante el curso y completo en vacaciones. Alemania: 140 días completos/280 medios al año; Francia: 964 h/año; Países Bajos: 16 h/sem; Reino Unido: hasta 20 h/sem.", fr: "La plupart des pays autorisent un emploi à temps partiel — 15–20 h/sem en cours, temps plein en vacances. Allemagne : 140 jours complets/280 demi par an. France : 964 h/an. Pays-Bas : 16 h/sem. Royaume-Uni : 20 h/sem.", de: "Die meisten Länder erlauben Teilzeitarbeit — 15–20 Std./Woche im Semester, Vollzeit in Ferien. DE: 140 ganze / 280 halbe Tage/Jahr; FR: 964 Std./Jahr; NL: 16 Std./Wo.; UK: bis 20 Std./Wo.", it: "Quasi ovunque part-time consentito — 15–20 h/sett. e tempo pieno in vacanza. DE: 140 giorni interi / 280 mezze; FR: 964 h/anno; NL: 16 h/sett.; UK: 20 h/sett.", pt: "Quase todos permitem part-time — 15–20 h/sem em aulas, integral em férias. DE: 140 dias inteiros/280 meios; FR: 964 h/ano; NL: 16 h/sem; UK: 20 h/sem.", pl: "Prawie wszędzie praca w niepełnym wymiarze — 15–20 h/tyg., pełny etat w wakacje. DE: 140/280 dni; FR: 964 h/rok; NL: 16 h/tyg.; UK: 20 h/tyg.", uk: "Зазвичай дозволено часткову зайнятість — 15–20 год/тиж під час семестру, повна — на канікулах. DE: 140/280 днів; FR: 964 год/рік; NL: 16 год/тиж; UK: до 20 год/тиж." },
    source: { label: "EU Immigration Portal", url: "https://immigration-portal.ec.europa.eu/" } },
  { id: "freelance", short: "It depends",
    q: { en: "Can I freelance on a residence permit?", es: "¿Puedo trabajar como freelance con permiso de residencia?", fr: "Puis-je être freelance avec un titre de séjour ?", de: "Darf ich mit Aufenthaltstitel freiberuflich arbeiten?", it: "Posso fare freelance con permesso di soggiorno?", pt: "Posso trabalhar como freelancer com autorização?", pl: "Czy mogę być freelancerem na karcie pobytu?", uk: "Чи можу я фрилансити з посвідкою?" },
    answer: { en: "A standard work or student permit usually only covers a specific employer. To freelance you normally need a self-employment permit (Germany: Freiberufler visa, Spain: cuenta propia, Portugal: D2). Doing freelance work on the wrong permit can void it.", es: "Un permiso normal solo cubre un empleador concreto. Para freelance suele hacer falta un permiso de autónomo (DE: Freiberufler; ES: cuenta propia; PT: D2). Hacerlo con el permiso equivocado puede invalidarlo.", fr: "Un permis classique ne couvre qu'un employeur. Pour freelance, il faut un permis indépendant (DE: Freiberufler ; ES: cuenta propia ; PT: D2). Le faire avec le mauvais permis peut l'annuler.", de: "Standardpermits decken meist nur einen Arbeitgeber. Für Selbstständigkeit braucht es ein Freiberufler-Visum (DE), cuenta propia (ES), D2 (PT). Falscher Permit-Status kann erlöschen.", it: "Un permesso standard copre solo un datore. Per freelance serve permesso da autonomo (DE: Freiberufler; ES: cuenta propia; PT: D2). Lavorare con permesso sbagliato lo annulla.", pt: "Permissão padrão cobre só um empregador. Para freelance precisa de visto de independente (DE Freiberufler, ES cuenta propia, PT D2). Usar errado invalida.", pl: "Standardowy permit obejmuje jednego pracodawcę. Do freelancingu potrzebny osobny status (DE: Freiberufler; ES: cuenta propia; PT: D2).", uk: "Стандартний дозвіл зазвичай — на одного роботодавця. Для фрилансу потрібен окремий статус (DE: Freiberufler; ES: cuenta propia; PT: D2)." } },
  { id: "stay-after-grad", short: "Usually yes",
    q: { en: "Can I stay after graduation?", es: "¿Puedo quedarme tras graduarme?", fr: "Puis-je rester après mes études ?", de: "Darf ich nach dem Studium bleiben?", it: "Posso restare dopo la laurea?", pt: "Posso ficar após formar-me?", pl: "Czy mogę zostać po studiach?", uk: "Чи можу я залишитися після випуску?" },
    answer: { en: "Most EU countries grant a post-study job-search permit of 9–18 months. Germany: 18 months. France: 12 months. Netherlands: 1 year (Zoekjaar). UK: 2-year Graduate visa. You usually have to apply before your student permit expires.", es: "La mayoría de la UE concede permiso de búsqueda de empleo de 9–18 meses. DE: 18; FR: 12; NL: 1 año (Zoekjaar); UK: visado Graduate 2 años. Solicítalo antes de que caduque el permiso de estudios.", fr: "La plupart des pays UE délivrent un permis de recherche d'emploi 9–18 mois. DE: 18 ; FR: 12 ; NL: 1 an (Zoekjaar) ; UK: visa Graduate 2 ans. Demandez avant l'expiration du permis étudiant.", de: "Die meisten EU-Länder bieten 9–18 Monate Arbeitsuchvisum nach dem Studium. DE: 18; FR: 12; NL: 1 Jahr (Zoekjaar); UK: 2 Jahre Graduate. Vor Ablauf des Studentenvisums beantragen.", it: "Quasi tutta la UE concede un permesso post-studio 9–18 mesi. DE: 18; FR: 12; NL: 1 anno (Zoekjaar); UK: 2 anni Graduate. Richiedi prima della scadenza.", pt: "Quase toda a UE concede permissão pós-estudo 9–18 meses. DE: 18; FR: 12; NL: 1 ano; UK: 2 anos Graduate.", pl: "UE zwykle daje 9–18 mies. na szukanie pracy po studiach. DE: 18; FR: 12; NL: 1 rok; UK: 2 lata Graduate.", uk: "Більшість країн ЄС дають 9–18 міс. на пошук роботи після диплома. DE: 18; FR: 12; NL: 1 рік; UK: 2 роки Graduate." } },
  { id: "schengen", short: "Yes",
    q: { en: "Can I travel through Schengen on my permit?", es: "¿Puedo viajar por Schengen con mi permiso?", fr: "Puis-je circuler dans Schengen avec mon titre ?", de: "Darf ich mit meinem Permit durch Schengen reisen?", it: "Posso viaggiare in Schengen con il permesso?", pt: "Posso viajar em Schengen com a autorização?", pl: "Czy mogę podróżować po Schengen z permitem?", uk: "Чи можу я подорожувати Шенгеном з посвідкою?" },
    answer: { en: "A residence permit from any Schengen country lets you travel to all 29 Schengen countries for up to 90 days in any 180-day period, for tourism. You can't work in another Schengen country without a separate permit.", es: "Un permiso de cualquier país Schengen te permite viajar a los 29 países hasta 90 días en 180, por turismo. No puedes trabajar en otro Schengen sin permiso aparte.", fr: "Un titre Schengen permet de circuler dans les 29 pays Schengen, 90 jours sur 180, en touriste. Pas de travail dans un autre pays Schengen sans permis distinct.", de: "Ein Aufenthaltstitel eines Schengen-Landes erlaubt Tourismus in allen 29 — 90 von 180 Tagen. Arbeit anderswo nur mit eigenem Permit.", it: "Un permesso di un paese Schengen consente turismo nei 29 paesi — 90 giorni su 180. Niente lavoro altrove senza permesso.", pt: "Autorização de qualquer país Schengen permite turismo nos 29 — 90 dias em 180. Trabalho noutro só com permissão própria.", pl: "Karta pobytu z dowolnego Schengen pozwala podróżować po 29 krajach — 90/180 dni. Praca w innym tylko z osobnym permitem.", uk: "Посвідка з будь-якої країни Шенгену дає туризм у 29 країнах — 90/180 днів. Робота в іншій — лише з окремим дозволом." },
    region: { en: "EU / Schengen", es: "UE / Schengen", fr: "UE / Schengen", de: "EU / Schengen", it: "UE / Schengen", pt: "UE / Schengen", pl: "UE / Schengen", uk: "ЄС / Шенген" } },
  { id: "family-join", short: "Usually yes",
    q: { en: "Can my partner join me?", es: "¿Puede venir mi pareja?", fr: "Mon/ma partenaire peut-il/elle me rejoindre ?", de: "Kann mein/e Partner/in nachziehen?", it: "Il mio partner può raggiungermi?", pt: "O meu parceiro pode juntar-se a mim?", pl: "Czy partner/ka może do mnie dołączyć?", uk: "Чи може партнер/ка приєднатися?" },
    answer: { en: "Most residence permits allow family reunification for spouses, registered partners and minor children. The sponsor usually has to prove enough income (typically the local minimum wage) and adequate housing. Processing can take 2–6 months.", es: "La mayoría permite reagrupación de cónyuges, parejas registradas e hijos menores. El sponsor suele probar ingresos (salario mínimo) y vivienda. Tarda 2–6 meses.", fr: "La plupart des titres permettent le regroupement pour conjoint, partenaire enregistré et enfants. Le garant prouve revenus (SMIC) et logement. 2–6 mois.", de: "Familiennachzug für Ehepartner, eingetragene Partner und minderjährige Kinder ist meist möglich. Sponsor weist Einkommen (Mindestlohn) und Wohnraum nach. 2–6 Monate.", it: "Quasi tutti i permessi consentono ricongiungimento per coniuge, partner registrato e figli minori. Sponsor: reddito (minimo) e alloggio. 2–6 mesi.", pt: "Quase todas as autorizações permitem reagrupamento de cônjuge, parceiro registado e filhos menores. Sponsor: rendimento (mínimo) e habitação. 2–6 meses.", pl: "Większość permitów umożliwia łączenie z małżonkiem, partnerem i dziećmi. Sponsor: dochód (płaca minimalna) i mieszkanie. 2–6 mies.", uk: "Більшість посвідок дозволяє возз'єднання з подружжям, зареєстрованим партнером і дітьми. Спонсор: дохід (мінімальна) та житло. 2–6 міс." } },
  { id: "drive", short: "It depends",
    q: { en: "Can I drive with my home country licence?", es: "¿Puedo conducir con mi carnet del país de origen?", fr: "Puis-je conduire avec mon permis d'origine ?", de: "Darf ich mit dem heimischen Führerschein fahren?", it: "Posso guidare con la patente del mio paese?", pt: "Posso conduzir com a minha carta de condução?", pl: "Czy mogę jeździć na prawie jazdy z kraju?", uk: "Чи можу я керувати з рідним посвідченням?" },
    answer: { en: "Inside the EU/EEA, your licence is valid as long as it's valid at home. From outside, most countries let you drive 6–12 months on your foreign licence (sometimes with an International Driving Permit) before requiring an exchange or local test.", es: "Dentro UE/EEE, vale mientras esté vigente. De fuera, casi todos permiten 6–12 meses (a veces con permiso internacional) antes de canjear o examinarse.", fr: "Dans l'UE/EEE, le permis est valable tant qu'il l'est au pays. Hors UE, 6–12 mois (parfois avec PCI) avant échange ou examen local.", de: "EU/EWR: gültig solange daheim gültig. Sonst meist 6–12 Monate (manchmal mit Int. Führerschein) vor Umtausch oder Prüfung.", it: "UE/SEE: valida finché lo è in patria. Da fuori: 6–12 mesi (a volte con permesso internazionale) prima di cambio o esame.", pt: "UE/EEE: válida enquanto válida em casa. De fora: 6–12 meses (às vezes carta internacional) antes de troca/exame.", pl: "UE/EOG: ważne dopóki ważne w kraju. Spoza: 6–12 mies. (czasem międzynarodowe) przed wymianą/egzaminem.", uk: "ЄС/ЄЕЗ: дійсне поки чинне вдома. Поза ЄС: 6–12 міс. (іноді з міжнародним) до обміну чи іспиту." } },
  { id: "open-bank", short: "Usually yes",
    q: { en: "Can I open a bank account before moving?", es: "¿Puedo abrir cuenta antes de mudarme?", fr: "Puis-je ouvrir un compte avant de partir ?", de: "Kann ich vor dem Umzug ein Konto eröffnen?", it: "Posso aprire un conto prima di trasferirmi?", pt: "Posso abrir conta antes de mudar?", pl: "Czy mogę założyć konto przed przeprowadzką?", uk: "Чи можу я відкрити рахунок до переїзду?" },
    answer: { en: "Digital banks (N26, Revolut, Wise, Bunq) let you open an account from abroad in minutes with just a passport. Traditional banks usually need your address registration first.", es: "Bancos digitales (N26, Revolut, Wise, Bunq) abren cuenta en minutos solo con pasaporte. Bancos tradicionales requieren registro de domicilio.", fr: "Néobanques (N26, Revolut, Wise, Bunq) : compte en quelques minutes avec passeport. Banques classiques : domicile requis.", de: "Digitalbanken (N26, Revolut, Wise, Bunq) öffnen Konten in Minuten nur mit Pass. Filialbanken brauchen meist Anmeldung.", it: "Banche digitali (N26, Revolut, Wise, Bunq) aprono in pochi minuti con passaporto. Banche tradizionali: serve la residenza.", pt: "Bancos digitais (N26, Revolut, Wise, Bunq) abrem em minutos só com passaporte. Tradicionais: precisam de morada.", pl: "Banki cyfrowe (N26, Revolut, Wise, Bunq) — konto w minuty z paszportem. Tradycyjne wymagają meldunku.", uk: "Цифрові банки (N26, Revolut, Wise, Bunq) — рахунок за хвилини з паспортом. Класичні вимагають реєстрації адреси." } },
  { id: "leave-return", short: "Usually no",
    q: { en: "Can I leave and re-enter while my permit is being processed?", es: "¿Puedo salir y volver mientras tramitan mi permiso?", fr: "Puis-je sortir et rentrer pendant le traitement du titre ?", de: "Darf ich während der Permit-Bearbeitung aus- und einreisen?", it: "Posso uscire e rientrare durante l'esame del permesso?", pt: "Posso sair e voltar enquanto a autorização é processada?", pl: "Czy mogę wyjechać i wrócić w trakcie rozpatrywania permitu?", uk: "Чи можна виїхати і повернутися під час оформлення посвідки?" },
    answer: { en: "Once you've applied for a residence permit, leaving the country before you get the card (or at least a fiktionsbescheinigung / récépissé) often means you can't re-enter. Always ask the immigration office for a re-entry confirmation first.", es: "Tras solicitar el permiso, salir antes de tener la tarjeta (o récépissé/Fiktionsbescheinigung) suele impedir reentrar. Pide siempre confirmación de reentrada.", fr: "Après dépôt, sortir avant d'obtenir la carte (ou récépissé/Fiktionsbescheinigung) empêche souvent de revenir. Demandez toujours une autorisation de réentrée.", de: "Nach Antragstellung kann Ausreise vor Erhalt der Karte (oder Fiktionsbescheinigung) die Wiedereinreise blockieren. Vorher Bestätigung einholen.", it: "Dopo la domanda, uscire prima della carta (o ricevuta) spesso impedisce il rientro. Chiedi sempre conferma di rientro.", pt: "Após pedido, sair antes do cartão (ou récépissé) muitas vezes impede o regresso. Peça sempre confirmação.", pl: "Po złożeniu wniosku wyjazd przed kartą (lub poświadczeniem) często blokuje powrót. Zawsze pytaj urząd.", uk: "Після подачі заяви виїзд до отримання картки (або довідки) часто блокує повернення. Завжди уточнюйте в офісі." } },
  { id: "marry-locally", short: "Yes",
    q: { en: "Can I get married to a local?", es: "¿Puedo casarme con alguien del país?", fr: "Puis-je me marier avec un·e local·e ?", de: "Darf ich eine/n Einheimische/n heiraten?", it: "Posso sposarmi con una persona del posto?", pt: "Posso casar com alguém local?", pl: "Czy mogę wziąć ślub z miejscowym?", uk: "Чи можу я одружитися з місцевим?" },
    answer: { en: "Foreigners can marry citizens in almost every country. You'll need a passport, a 'no impediment to marry' certificate from your home country (apostilled and translated), and sometimes a residence proof.", es: "Extranjeros pueden casarse con ciudadanos casi en todas partes. Necesitas pasaporte, fe de soltería apostillada y traducida, y a veces prueba de residencia.", fr: "Les étrangers peuvent presque partout épouser un·e citoyen·ne. Il faut passeport, certificat de non-empêchement (apostillé et traduit) et parfois preuve de résidence.", de: "Ausländer können fast überall Einheimische heiraten. Pass, Ehefähigkeitszeugnis (mit Apostille und Übersetzung), manchmal Wohnsitznachweis.", it: "Stranieri possono sposare cittadini quasi ovunque. Servono passaporto, nulla osta al matrimonio (con apostille e traduzione) e a volte residenza.", pt: "Estrangeiros podem casar com cidadãos quase em todo o lado. Passaporte, certidão de não-impedimento (apostilada/traduzida), por vezes morada.", pl: "Cudzoziemcy mogą poślubić obywateli niemal wszędzie. Paszport, zaświadczenie o zdolności do zawarcia małżeństwa (apostille + tłumaczenie), czasem meldunek.", uk: "Іноземці можуть одружитися з громадянами майже всюди. Паспорт, довідка про відсутність перешкод (з апостилем і перекладом), іноді — реєстрація." } },
  { id: "permanent-residency", short: "Usually yes",
    q: { en: "Can I get permanent residency?", es: "¿Puedo obtener residencia permanente?", fr: "Puis-je obtenir la résidence permanente ?", de: "Kann ich Daueraufenthalt bekommen?", it: "Posso ottenere la residenza permanente?", pt: "Posso obter residência permanente?", pl: "Czy mogę uzyskać pobyt stały?", uk: "Чи можу я отримати постійний дозвіл?" },
    answer: { en: "Most countries grant permanent residency after 5 years of continuous legal stay (EU long-term resident status). Germany: 21–33 months for skilled workers with B1 German. Spain: 5 years. Portugal: 5 years.", es: "La mayoría tras 5 años de estancia legal (residente UE de larga duración). DE: 21–33 meses con B1; ES: 5 años; PT: 5 años.", fr: "Souvent après 5 ans de séjour légal (résident UE longue durée). DE: 21–33 mois si B1 ; ES: 5 ans ; PT: 5 ans.", de: "Meist nach 5 Jahren legalem Aufenthalt (EU-Daueraufenthalt). DE: 21–33 Monate für Fachkräfte mit B1; ES/PT: 5 Jahre.", it: "Di solito dopo 5 anni di soggiorno legale (lungo soggiornante UE). DE: 21–33 mesi con B1; ES/PT: 5 anni.", pt: "Geralmente após 5 anos legais (residente UE longa duração). DE: 21–33 meses com B1; ES/PT: 5 anos.", pl: "Zwykle po 5 latach legalnego pobytu (rezydent długoterminowy UE). DE: 21–33 mies. dla wykwalifikowanych z B1; ES/PT: 5 lat.", uk: "Зазвичай після 5 років легального проживання (довгостроковий резидент ЄС). DE: 21–33 міс. для фахівців з B1; ES/PT: 5 років." } },
];

