// ------- HOOK -------
export function useLocalizedExtras() {
  const [lang] = useLang();
  return useMemo(() => {
    const T = (t: Tx | undefined) => pk(t, lang);
    const A = (a: Tx[] | undefined) => (a ? a.map((t) => pk(t, lang)) : []);
    return {
      lang,
      terms: TERMS_L.map((e) => ({
        id: e.id,
        term: T(e.term),
        bureaucratic: T(e.bureaucratic),
        plain: T(e.plain),
        example: e.example ? T(e.example) : undefined,
        aliases: e.aliases ?? [],
      })),
      legal: LEGAL_L.map((q) => ({
        id: q.id,
        q: T(q.q),
        short: q.short,
        answer: T(q.answer),
        region: q.region ? T(q.region) : undefined,
        source: q.source,
      })),
      costPresets: COST_PRESETS_L.map((p) => ({ ...p, label: T(p.label) })),
      costRows: COST_ROWS_L.map((r) => ({ id: r.id, max: r.max, label: T(r.label) })),
      costDisclaimer: T(COST_DISCLAIMER),
      compareRows: COMPARE_L.map((r) => ({
        flag: r.flag,
        country: T(r.country),
        studentHours: T(r.studentHours),
        visaTime: T(r.visaTime),
        workRights: T(r.workRights),
      })),
      compareHead: {
        country: T(COMPARE_HEAD.country),
        studentHours: T(COMPARE_HEAD.studentHours),
        visaTime: T(COMPARE_HEAD.visaTime),
        workRights: T(COMPARE_HEAD.workRights),
      },
      compareNote: T(COMPARE_NOTE),
      help: {
        subtitle: T(HELP_L.pageSubtitle),
        quickContacts: T(HELP_L.quickContacts),
        lostHeader: T(HELP_L.lostHeader),
        tipLabel: T(HELP_L.tipLabel),
        tipText: T(HELP_L.tipText),
        emergencyTitle: T(HELP_L.emergencyTitle),
        emergencyNote: T(HELP_L.emergencyNote),
        lostTitle: T(HELP_L.lostTitle),
        lostValue: T(HELP_L.lostValue),
        lostNote: T(HELP_L.lostNote),
        embassyTitle: T(HELP_L.embassyTitle),
        embassyValue: T(HELP_L.embassyValue),
        embassyFallback: T(HELP_L.embassyFallback),
        embassyTemplate: T(HELP_L.embassyTemplate),
        euTitle: T(HELP_L.euTitle),
        euNote: T(HELP_L.euNote),
        steps: A(HELP_L.steps),
      },
    };
  }, [lang]);
}